var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"대적자라는 존재가 있다네.","JPN":"敵対者という存在がいる。","ENG":"There is a being called the Antagonist.","TWN":"有一個叫敵對者的存在。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계의 의지로부터 선택을 받은 존재지.","JPN":"この世界の意志から選ばれた存在だ。","ENG":"This being is chosen by the will of this world.","TWN":"他是被這個世界的意志所選中的。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대적자……?","JPN":"敵対者……？","ENG":"Antagonist...?","TWN":"敵對者……？"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"쉽게 말해, 마왕으로부터 세계를 구하는 동화 속 용사님이야.","JPN":"わかりやすく言うと、魔王から世界を救うおとぎ話の中の勇者だ。","ENG":"Simply put, the Antagonist is the hero from fairytales who saves the world from the Demon Lord.","TWN":"簡單來說，敵對者就是從魔王手中拯救世界的童話英雄。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"존 스미스라는 이방인을 만난 뒤로 나는 줄곧 대적자라는 존재를 찾아왔네.","JPN":"ジョン・スミスという異邦人に会ってから、私はずっと敵対者という存在を探してきた。","ENG":"After meeting the stranger who goes by John Smith, I have been searching for this Antagonist.","TWN":"自從遇到那名叫約翰·史密斯的異鄉人後，我一直在尋找所謂的敵對者。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"언젠가 우리 세계에 닥쳐 올 위기에 대처하기 위해서.","JPN":"いつか私たちの世界に訪れる危機に備えるために。","ENG":"So that we can prepare for the crisis this world might face one day.","TWN":"為了應對未來可能降臨我們世界的危機。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 탐정인 나에게도 쉬운 일이 아니었어. 그 어떤 단서조차 없었거든.","JPN":"だがそれは、探偵である私にも容易なことではなかった。まったく手がかりがなかったからな。","ENG":"It is no easy task for even a detective like me. There seems to be no clue.","TWN":"這對我這樣偵探來說也不是件容易的事。因為根本沒有任何線索。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 마침내 한 여인을 찾아냈지.","JPN":"だが、やっと一人の女性を探し出した。","ENG":"But then, I finally found a woman.","TWN":"但最終我還是找到了一個女人。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세상에 내가 풀어내지 못하는 수수께끼 같은 건 없으니까.","JPN":"この世界に私が解けない謎など、ないのだから。","ENG":"Because there is no mystery I can't solve in this world.","TWN":"果然，這個世界上沒有我解不開的謎題。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 비록 멀리서 바라볼 뿐이지만 항상 응원하고 있어.","JPN":"そのとおりだ。ただ遠くから見守っているだけだが、いつも応援している。","ENG":"Although I saw from afar, I'll always be cheering for you.","TWN":"是的。雖然只能遠遠地看著，但我一直在為你加油。"},"stage":{"bg":"BACKSTREET3","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"팬이니까 말이야, 자네의.","JPN":"ファンだからな、君の。","ENG":"I'm actually a fan of yours.","TWN":"史旺，我是你的粉絲。"},"stage":{"bg":"BACKSTREET3","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……설마.","JPN":"……まさか。","ENG":"...It can't be.","TWN":"……難道。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이 내 팬을 자처했던 이유가……?","JPN":"あなたが私のファンを名乗った理由って……？","ENG":"Is that why you said that you were my fan...?","TWN":"你自稱是我粉絲的理由是……？"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 역시 망설일 수밖에 없었다네.","JPN":"だが、やはり躊躇うしかなかったんだよ。","ENG":"But I was hesitating.","TWN":"但我依舊心存顧忌。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계의 모든 미지를 상대한다는 건, 그만큼 고독한 일이거든.","JPN":"この世界のすべての未知を相手するということは、すごく孤独な仕事だからな。","ENG":"Tackling all the unknown in this world is a lonely task, after all.","TWN":"面對這個世界的所有未知，實在是件孤獨的事情。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 누구보다도 내가 가장 잘 알고 있으니까.","JPN":"それは誰よりも私が一番よく知っている。","ENG":"I should know that better than anyone.","TWN":"因為這件事我比任何人都清楚。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마석을 정제하여 순도 높은 각성제와 배합한 <color=#ffd34c>주사액</color>이라네.","JPN":"魔石を精製して高純度の覚醒剤と調合した<color=#ffd34c>注射液</color>だ。","ENG":"It's a <color=#ffd34c>concoction</color> made of refined Mana Stones and high-purity stimulants.","TWN":"那是將魔石精煉後與高純度興奮劑混合製成的<color=#ffd34c>注射液</color>。"},"stage":{"bg":"ROOM_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수년 전, 내 오랜 벗이 이곳을 떠나기 전에 만들어 둔 거지.","JPN":"数年前、私の旧友がここを出る前に作っておいたものさ。","ENG":"Years ago, an old friend of mine made it before leaving this place.","TWN":"幾年前，我的一個老友在離開這裡之前製作的。"},"stage":{"bg":"ROOM_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이게 없으면, 이제 정상적인 생활이 불가능하거든.","JPN":"もうこれがないと、正常な暮らしができなくてね。","ENG":"Without it, I'm unable to function normally now.","TWN":"沒有這個，現在就無法正常生活了。"},"stage":{"bg":"ROOM_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금 돌이켜보면 어리석은 판단이었어.","JPN":"今思い返せば、愚かな判断だった。","ENG":"It was a foolish decision looking back at it now.","TWN":"現在回想起來，那是個愚蠢的決定。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네에게 더 많은 걸 알려주고, 더 많은 인연을 쌓게 해야 했어…….","JPN":"君にもっとたくさんのことを教えて、より多くの絆を築かせてあげるべきだったんだ……","ENG":"I should've told you more and built a relationship with you…","TWN":"應該告訴你更多，建立更多的聯繫……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"망각의 여신에게 미움받는 자네인 만큼, 자네에게 소중한 기억을 남겨줬어야 했어.","JPN":"君は忘却の女神に嫌われているから、君に大切な思い出を残してあげるべきだった。","ENG":"For you are shunned by the goddess of oblivion, I should've left you with precious memories.","TWN":"既然你被遺忘女神所厭惡，我本該為你留下珍貴的記憶。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이런 결말이 올 줄 미리 알았다면…….","JPN":"こんな結末が来るとわかっていたなら……","ENG":"If only I had known it would turn out this way...","TWN":"如果早知道會有這樣的結局……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그거 알고 있나, 스완?","JPN":"知っているか？　スワン。","ENG":"Did you know, Swan?","TWN":"你知道嗎，史旺？"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"백조는 죽기 전에 단 한 번. 아름답게 운다고 하지.","JPN":"白鳥は死ぬ前にたった一度。美しく鳴くらしい。","ENG":"The bird of the same name is said to let out a single beautiful cry right before its death.","TWN":"據說天鵝在死前會發出它這一生中最淒美動聽的叫聲。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 모리어티 교수는 심야의 살인마를 최후의 걸작으로 삼았지만.","JPN":"マグヌム・オプス。モリアーティ教授は深夜の殺人鬼を最後の傑作にしていたが、","ENG":"Magnum Opus. Professor Moriarty claimed that the Midnight Killer was his final masterpiece.","TWN":"偉大傑作。莫里蒂教授將午夜殺人魔視為他最後的傑作。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계가 남긴 진정한 <color=#ffd34c>최후의 걸작</color>은 바로 자네라네.","JPN":"この世界が残した真の<color=#ffd34c>最後の傑作</color>は君だ。","ENG":"But to this world, the true <color=#ffd34c>final masterpiece</color> is none other than you.","TWN":"但對這個世界來說，它所留下的真正的<color=#ffd34c>最後的傑作</color>，就是你啊。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인…….","JPN":"アバーライン……","ENG":"Abberline...","TWN":"艾伯林……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 이제 이 사진은 돌려주도록 하지.","JPN":"だから、もうこの写真は返そう。","ENG":"So, I think it's time that I returned this photo to its owner.","TWN":"所以現在該把這張照片還給你了。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>아이린 애들러</color>, 강철 같은 영혼을 가진 아름다운 여인이여.","JPN":"<color=#ffd34c>アイリーン・アドラー</color>、鋼のような魂を持つ美しい女性よ。","ENG":"<color=#ffd34c>Irene Adler</color>. You are a beautiful woman with a soul of steel.","TWN":"<color=#ffd34c>愛琳·艾德勒</color>，擁有鋼鐵般靈魂的美麗女子。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"……치사해요. 애버라인.","JPN":"……ずるいです、アバーライン。","ENG":"...You're mean, Abberline.","TWN":"……真卑鄙啊，艾伯林。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"그 이름으로 불리던 시절은 끝났다고요.","JPN":"その名前で呼ばれていた時代はもう終わったんですよ。","ENG":"My days of being called by that name are long gone.","TWN":"那個名字的時代已經結束了。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"기껏 이름까지 버리고서 새로운 무대로 도망쳤는데.","JPN":"せっかく名前を捨ててまで新しい舞台に逃げたのに。","ENG":"I gave up that name and ran away to a new stage.","TWN":"我好不容易連名字都拋棄了，逃到了新的舞台。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"무명 시절 이름으로 부르는 건 너무하다고요.","JPN":"無名時代の名前で呼ぶなんてひどいじゃないですか。","ENG":"It's low even for you to call me by the name when I was no one.","TWN":"對我直呼那個名字也太過分了。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그렇지 않아.","JPN":"ふふ、そんなことはない。","ENG":"Haha. That's not true.","TWN":"哈哈。不。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아름다운 이름이라고 생각해, 아이린.","JPN":"美しい名前だと思うよ、アイリーン。","ENG":"I think it's a beautiful name, Irene.","TWN":"我覺得這是個美麗的名字，愛琳。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"도망치는 게 항상 잘못된 건 아니라네.","JPN":"逃げることが常に間違っているわけではない。","ENG":"Running away is not always wrong.","TWN":"逃跑並不總是錯的。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 런던에 오지 않았다면, 자네와 나는 결국 만날 수 없었을 테니까.","JPN":"君がロンドンに来ていなければ、結局君と私は出会えなかったのだからな。","ENG":"If you hadn't come to London, you and I would've never met.","TWN":"如果你沒有來倫敦，我們最終是不會相遇的。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까 이번에도 도망치게.","JPN":"だから今回も逃げたまえ。","ENG":"So, run away again.","TWN":"所以，這次也逃跑吧。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"추하더라도, 힘겹더라도 끝까지 도망쳐서 살아 남는 거야.","JPN":"惨めでもつらくても、最後まで逃げて生き残るのだ。","ENG":"Even if it's ugly, even if you face hardship, run and survive.","TWN":"即使狼狽，即使艱難，也要逃到最後，活下來。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리 세계는 여기서 끝나더라도, 최후의 걸작인 자네가 살아남는다면 우리의 승리라네.","JPN":"私たちの世界はここで終わっても、最後の傑作である君が生き残ったなら私たちの勝利だ。","ENG":"Our world might end here, but it will be our victory if you, the final masterpiece, survive.","TWN":"即使我們的世界在此終結，只要你這幅最後的傑作能活下來，那就是我們的勝利。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"망각의 여신에게 미움받는 자네라면…….","JPN":"忘却の女神に嫌われている君なら……","ENG":"You are not blessed by the goddess of oblivion...","TWN":"如果你是被遺忘女神所厭惡之人……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"보이지 않는 실타래처럼 얽힌 세계의 법칙을 언젠가 간파해 낼 수 있을지도 모르니까.","JPN":"目に見えない糸のように絡まっている世界の法則を、いつか見抜けるかもしれないからな。","ENG":"So, you might be able to figure out the law of the world that are intertwined by invisible threads.","TWN":"也許有一天你能看穿像無形線團般糾纏的世界法則。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"여기서 북쪽으로 조금만 더 가면…….","JPN":"ここから北にもう少し行くと……","ENG":"If you keep heading north...","TWN":"從這裡再往北走一點……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계의 것이 아닌 유적이 있다네. 어느 사건을 통해 알게 된 곳이지.","JPN":"この世界のものではない遺跡がある。とある事件で知った場所だ。","ENG":"There will be ruins that are not of this world. I learned about that place through another case.","TWN":"有一個不屬於這個世界的遺跡。我通過某個案件得知了那裡。"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"언제부터 거기 있었고, 어떤 문명의 유적인지는 아무도 모르지만…….","JPN":"いつからそこにあって、どんな文明の遺跡なのか知る者は誰もいないが……","ENG":"I don't know how long it has been there, or from which civilization...","TWN":"沒人知道它從什麼時候開始存在，也不知道它屬於哪個文明的遺跡……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 틀림없이 다른 세계로 통하는 <color=#ffd34c>문</color>…….","JPN":"それは間違いなく別の世界に通じる<color=#ffd34c>扉</color>……","ENG":"But I do know that it is a <color=#ffd34c>door</color> to another world...","TWN":"但我知道那肯定是通往<color=#ffd34c>另一個世界</color>的門……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그럼 같이 가요!","JPN":"じゃ、じゃあ一緒に行きましょう！","ENG":"Th-then come with me!","TWN":"那、那我們一起去吧！"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"제가 부축해 드릴 테니까……!","JPN":"私が支えますから……！","ENG":"I'll help you...!","TWN":"我來扶你……！"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니…….","JPN":"いや……","ENG":"No...","TWN":"或者……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아무래도……. 그럴 수는 없을 것 같군…….","JPN":"どうやら……それはできそうにない……","ENG":"It seems... that will not be possible...","TWN":"……好像不太可能……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"너무 피곤해서 말이지…….","JPN":"少し、疲れててな……","ENG":"I'm too tired, you see...","TWN":"我太累了……"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인……?","JPN":"アバーライン……？","ENG":"Abberline...?","TWN":"艾伯林……？"},"stage":{"bg":"SWANSONG_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L22_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"저도 언니의 눈을 빌려, 이 세계를 쭉 지켜봐 왔지만 의외네요.","JPN":"私もお姉ちゃんの目を借りて、この世界をずっと見守ってきましたけど、意外ですね。","ENG":"I too have borrowed your vision and have kept an eye on this world, but it is unusual.","TWN":"我也借用了姊姊的眼睛，一直在觀察這個世界，真是出乎意料啊。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"설마, 당신 같은 가녀린 소녀가 이 세계의 선택을 받은 사람일 줄은 몰랐네요.","JPN":"まさか、あなたのようなか弱い少女がこの世界に選ばれし人だとは。","ENG":"Who would've thought that a frail girl like you would be the chosen one.","TWN":"沒想到，像你這樣纖弱的少女竟然是被這個世界選中的人。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"스완 클레어라고 했나요?","JPN":"スワン・クレアでしたね。","ENG":"Swan Claire, was it?","TWN":"你是叫史旺·克萊爾嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"누가 봐도 그 잘난 탐정이 대적자의 운명을 타고난 자가 아닐까 싶었는데 말이죠.","JPN":"誰が見てもあの探偵が敵対者の運命を持つ者だと思っていたのですが。","ENG":"I was almost certain that the detective would be the one destined with the Antagonist's fate.","TWN":"誰看了都會覺得那個自命不凡的偵探才是天生的敵對者吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군요. 당신이 이 세계를 침공한 마왕…….","JPN":"そうですね。あなたがこの世界を侵攻した魔王……","ENG":"I see. So, you are the Demon Lord who has invaded this world...","TWN":"原來如此。你就是入侵這個世界的魔王……"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"제가 이 세계의 대적자라는 걸 알고 계시니, 이야기가 빠르겠군요.","JPN":"私がこの世界の敵対者だということをご存じなら、話が早いでしょう。","ENG":"Since you already know that I'm this world's Antagonist, it makes this easier for me.","TWN":"既然你知道我是這個世界的敵對者，那事情就簡單了。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"정말이지. 저를 너무 얕보고 있어요, 애버라인.","JPN":"まったく。私を甘く見すぎですよ、アバーライン。","ENG":"You have really underestimated me, Abberline.","TWN":"你太小看我了，艾伯林。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"도망치는 것만으로는 아무것도 바꿀 수 없어요.","JPN":"逃げるだけでは何も変えられません。","ENG":"Running away can't change anything.","TWN":"只是一味地逃避，最終不會改變任何事情。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"그건 지금껏 도망쳐왔던 제가 가장 잘 알고 있죠.","JPN":"それはずっと逃げてきた私が一番よくわかってるんです。","ENG":"I know because I have been on the run for all this time.","TWN":"而我這個一直在逃避的人最清楚不過了。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"당신이 절 진정한 파트너라고 생각했다면, 도망치라고 하지 않았을 거예요.","JPN":"あなたが私のことを真のパートナーだと思っていたなら、逃げろなんて言わなかったはずです。","ENG":"If you truly think of me as your partner, then you wouldn't have said that to me.","TWN":"如果你真的把我當成搭檔，就不會讓我逃跑了。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"탐정은 죽었습니다.","JPN":"探偵は死にました。","ENG":"The detective is dead.","TWN":"偵探死了。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 저는 이 자리에 싸우러 온 게 아니에요.","JPN":"そして、私は戦うためにこの場に来たわけではありません。","ENG":"And I am not here to fight.","TWN":"而我不是來這裡打架的。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 오히려 반대죠.","JPN":"いや、むしろその逆です。","ENG":"It's actually the opposite.","TWN":"不，恰恰相反。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"배우로서 당신과 전속 계약을 맺으러 왔습니다. 마왕이여.","JPN":"俳優として、あなたと専属契約をするために参りました。魔王。","ENG":"I have come here to create an exclusive contract with you as an actress, Demon Lord.","TWN":"作為演員，我是來和你簽訂專屬契約的。魔王大人。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"저는 지금 이 순간부터 악을 연기합니다.","JPN":"私は今、この瞬間から悪を演じます。","ENG":"From this moment on, I will act as the villain.","TWN":"從此刻起，我將扮演邪惡。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"당신의 진정한 벗, <color=#ffd34c>존 왓슨</color>이 그랬던 것처럼.","JPN":"あなたの真なる友、<color=#ffd34c>ジョン・ワトソン</color>がそうだったように。","ENG":"Just like your true friend, <color=#ffd34c>John Watson</color>, did.","TWN":"就像你真正的朋友，<color=#ffd34c>約翰·華生</color>那樣。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"전속 계약이라고요? 제가 왜 당신과 계약을 맺어야 되죠?","JPN":"専属契約？　どうして私があなたと契約を交わさなければならないのですか？","ENG":"An exclusive contract? Why would I make a contract with you?","TWN":"專屬契約？我為什麼要和你簽這種東西？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"여기서 당신을 죽이면 모든 게 쉽게 끝날 텐데요.","JPN":"ここであなたを殺せば、簡単にすべてが終わるというのに。","ENG":"Everything will end so easily by just killing you.","TWN":"如果在這裡殺了你，一切就會輕鬆結束了。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄요, 그건 이상하네요.","JPN":"さあ、それはおかしいですね。","ENG":"Well, that's odd.","TWN":"是麼，這可真是奇怪。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇게 손쉽게 세계를 멸망시킬 수 있다면 당신은 어째서 카넬리안을 조종한 거죠?","JPN":"そうやって簡単に世界を滅ぼすことができるのなら、あなたはどうしてカーネリアンを操ったのですか？","ENG":"If you could destroy this world so easily, then why did you control Carnelian?","TWN":"如果你能那麼輕易地毀滅世界，那為什麼要通過操縱卡內利安呢？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"구태여 심야의 살인마 같은 촌극을 벌일 필요가 없었을 텐데요?","JPN":"あえて深夜の殺人鬼のような茶番を見せる必要もなかったはずです。","ENG":"Moreover, there wouldn't have been a need to stage such a crude play like the Midnight Killer, no?","TWN":"根本沒必要上演午夜殺人魔那樣的鬧劇吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"추측컨대, 당신은 어떠한 경위로 온전한 힘을 쓸 수 없는 상태가 아닐까요?","JPN":"あなたは、とある経緯でまともに力を使えない状態ではないのでしょうか。","ENG":"My guess is that you, for some reason, have not regained all of your powers.","TWN":"我猜測，你是因為某種原因無法使用全部的力量。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇기 때문에 이렇게 번거로운 절차가 필요했던 거겠죠.","JPN":"そのためにこうやって手の込んだ手順が必要だったのでしょう。","ENG":"And that's why you went through all that trouble.","TWN":"所以才需要這麼繁瑣的程式吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 앞에서 무엄하구나. 미천한 계집이여.","JPN":"王の前でなんて無礼なことを。この卑しい小娘が。","ENG":"How dare you insult the queen, you lowly girl.","TWN":"在王的面前竟敢如此放肆，卑微的女人。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"더 혀를 놀렸다간, 단칼에 목을 잘라주지.","JPN":"それ以上喋れば、一気に首を斬るぞ。","ENG":"Keep running your tongue and I'll slice your head clean off your shoulders.","TWN":"再多說一句，我就一刀砍下你的頭。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L1_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"괜찮아요, 언니.","JPN":"大丈夫ですよ、お姉ちゃん。","ENG":"It's okay, Sola.","TWN":"沒關係，姊姊。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"흐음. 그 같잖은 목숨이 아까워서 허세 부리는 꼴이 참 우습네요.","JPN":"うーん、そのつまらない命を守るために虚勢を張る姿がとても滑稽です。","ENG":"Hmm. How amusing to see you be so pretentious about saving your worthless life.","TWN":"姆。你為了可笑的性命而虛張聲勢的樣子真是滑稽。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제 편을 들겠다니, 당신 같은 대적자는 처음이에요.","JPN":"私の味方になろうなんて、あなたのような敵対者は初めてです。","ENG":"I've never had an Antagonist ask to be on my side.","TWN":"說要站在我這邊，像你這樣的敵對者還是第一次見。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"맞아요, 저는 제 목숨이 아까워요.","JPN":"そうです。私は自分の命が大事ですよ。","ENG":"You're right. I do care about my life.","TWN":"沒錯，我確實很惜命。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 비굴한 모습을 보일 바에는 차라리 죽어 버리는 게 낫죠.","JPN":"でも、卑屈な姿を見せるくらいならいっそ死んでしまうほうがマシです。","ENG":"But I'd rather die than grovel at your feet.","TWN":"但與其卑躬屈膝，不如乾脆去死來得痛快。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"왜냐하면…….","JPN":"なぜなら……","ENG":"Because...","TWN":"因為……"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"누구보다 우아하게 보이고 싶은 건, 배우의 본질이니까.","JPN":"誰よりも優雅に見せたいのは、俳優の本質ですから。","ENG":"It is in an actress' essence to be seen as more elegant than anyone else.","TWN":"想比任何人都要優雅，這是演員的本質。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"이건 어디까지나 계약이에요.","JPN":"これはあくまでも契約です。","ENG":"This is merely a contract.","TWN":"這只是契約而已。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"당신을 위해 심야의 살인마가 되어드리도록 하죠.","JPN":"あなたのために、深夜の殺人鬼になって差し上げましょう。","ENG":"I will become the Midnight Killer for you.","TWN":"我會為了你，成為午夜殺人魔。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"배우로서 당신이 시키는 일이라면 어떤 배역이든 맡겠습니다.","JPN":"俳優として、あなたの指示ならどんな配役でも引き受けます。","ENG":"As an actress, I will take on any role you ask of me.","TWN":"作為演員，只要是你安排的角色，我都會接受。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"설령, 그게 다른 세계를 짓밟는 일이라고 할지라도…….","JPN":"例え、それが別の世界を踏みつけることだとしても……","ENG":"Even if it means tearing apart other worlds.","TWN":"哪怕表示要踐踏其他世界……"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"기꺼이 협조해드리죠.","JPN":"喜んでご協力いたしましょう。","ENG":"I will be more than happy to cooperate.","TWN":"我也樂意協助你們。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"설령, 연기라고 해도 죄를 저지른다면 언젠가 죗값을 치러야겠죠.","JPN":"例え演技だとしても、罪を犯せばいつかは罪滅ぼしをしなければいけません。","ENG":"Even if it's just acting, I will have to pay for the sins I committed someday.","TWN":"即使是演戲，如果犯了罪，總有一天也是要償還罪行的。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 저는 절대 도망치지 않을 거예요.","JPN":"ですが、私は絶対に逃げません。","ENG":"However, I will not run away.","TWN":"但是我絕不會逃跑。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"……그래서?","JPN":"……それで？","ENG":"...So?","TWN":"……所以？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"계약이라면 바라는 것도 있겠죠?","JPN":"契約なら望みがあるのでしょう？","ENG":"I am sure there is something you wish in return.","TWN":"既然是契約，那你肯定也有要求吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신의 세계를 무너트린 저에게 당신은 무엇을 바라는 걸까요?","JPN":"あなたの世界を崩壊させた私に、あなたは何を望んでいるのですか？","ENG":"What do you want from someone who has collapsed your world?","TWN":"對於摧毀你世界的我，你還指望什麼呢？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"그거야 당연하잖아요?","JPN":"それは決まっています。","ENG":"It’s obvious, isn’t it?","TWN":"那個很明顯吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"당신이 무너트린 저의 세계를 돌려주세요. 그게 제 유일한 계약 조건이에요.","JPN":"あなたが崩壊させた私の世界を返してください。それが私の唯一の契約条件です。","ENG":"I want you to give me back the world you destroyed. That's my one condition.","TWN":"請把你摧毀了的我的世界還給我。這是我唯一的契約條件。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"만약 그로 인해, 제 손이 더러워져 붉게 물들지라도.","JPN":"もしそのせいで、私の手が汚れ赤く染まったとしても。","ENG":"No matter if my hands get dirtied in blood because of it.","TWN":"即使因此，我的手會被染得血紅。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"언젠가, 어느 세계에서든 다시 만나게 되면 그땐 제 손을 피하지 말아주세요.","JPN":"いつか、どんな世界であろうと、再会することになれば、その時には私を避けないでくださいね。","ENG":"I only hope that you will not avoid my hand when we meet again one day elsewhere.","TWN":"如果有一天，在某個世界再次相遇時，請不要避開我的雙手。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"프레드릭 애버라인.","JPN":"フレデリック・アバーライン。","ENG":"Fredrick Abberline.","TWN":"弗雷德里克·艾伯林。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"아니…….","JPN":"いや……","ENG":"No...","TWN":"或者……"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"후후, 재밌네요.","JPN":"ふふ、面白いですね。","ENG":"Haha, interesting.","TWN":"呼呼，有趣呢。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신이 속으로 무슨 꿍꿍이를 꾸미는지는 모르겠지만, 전속 계약이라고 했죠?","JPN":"あなたが何を企んでいるのかはわかりませんが、専属契約と言いましたね？","ENG":"I don't know what it is that you're scheming, but you want an exclusive contract?","TWN":"我不知道你心裡在打什麼算盤，但你說的是專屬契約，對吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그렇다면 당신 목숨은 계약과 별도로 제가 맡도록 하죠.","JPN":"それなら、あなたの命は契約とは別に私が預かることにしましょう。","ENG":"Then, besides the contract, I will hold on to your life.","TWN":"那麼除了契約外，你的性命也由我來負責吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"커흑……!!","JPN":"がはっ……！！","ENG":"Kuh...!!","TWN":"咳！！"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"방금 당신의 심장을 재조립했어요.","JPN":"今、あなたの心臓を組み直しました。","ENG":"Just now, I have reassembled your heart.","TWN":"剛剛我重新組裝了你的心臟。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이걸로 계약은 성사되었어요. 마음만 먹으면 언제든 위약금을 받아갈 수 있겠죠.","JPN":"これで契約成立です。その気になれば、いつでも違約金をもらうことができるでしょう。","ENG":"With this, the contract is done. I will be able to get my compensation at will.","TWN":"這樣契約就成立了。只要我願意，隨時都可以拿到違約金。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그러니 앞으로 멋진 무대를 보여주길 바랄게요.","JPN":"ですので、これから素敵な舞台を見せてくださいね。","ENG":"So, I hope you show me a great performance.","TWN":"所以希望你以後能為我展現出精彩的舞台。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"대적자, 스완 클레어.","JPN":"敵対者、スワン・クレア。","ENG":"Antagonist, Swan Claire.","TWN":"敵對者，史旺·克萊爾。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"……물론이예요.","JPN":"……もちろんです。","ENG":"...Of course.","TWN":"……當然了。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"저는 런던……. 아니, 이젠 이 세계 제일의 프리마돈나랍니다.","JPN":"私はロンドン……いいえ、今はこの世界で一番のプリマドンナです。","ENG":"I am London's, no, now the world's greatest prima donna.","TWN":"我是倫敦……不，現在是這個世界最棒的女主角。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 당신에게 최고의 무대를 선사해드리죠.","JPN":"だから、あなたに最高の舞台をお送りいたしましょう。","ENG":"I will give you the best performance.","TWN":"那麼，我將為你獻上最精彩的舞台。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"IRENE_SWANSONG_NPC_NULL","text":{"KOREA":"마왕, 타기리온.","JPN":"魔王、タギリオン。","ENG":"Demon Lord Thagirion.","TWN":"魔王，塔基里翁。"},"stage":{"bg":"CORRIDOR_09","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"IRENE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};